import { Redirect } from 'expo-router';
import { View } from 'react-native';

import { useAuthStore } from '@/store/authStore';

export default function Index() {
  const isAuthenticated = useAuthStore((s) => s.isAuthenticated);
  const isInitialized = useAuthStore((s) => s.isInitialized);

  if (!isInitialized) return <View style={{ flex: 1, backgroundColor: '#fdfdfd' }} />;

  return (
    <Redirect href={isAuthenticated ? '/(tabs)/home' : '/(auth)/welcome'} />
  );
}

import { useEffect, useRef, useState } from 'react';
import { FlatList, Text, View } from 'react-native';

const ITEM_HEIGHT = 56;
const VISIBLE = 5;
const HALF = Math.floor(VISIBLE / 2);
export const GOAL_MAX = 200;

const ITEMS: (number | null)[] = [
  ...Array<null>(HALF).fill(null),
  ...Array.from({ length: GOAL_MAX }, (_, i) => i + 1),
  ...Array<null>(HALF).fill(null),
];

type Props = {
  initialValue: number;
  onChange: (value: number) => void;
};

export function GoalScrollPicker({ initialValue, onChange }: Props) {
  const ref = useRef<FlatList<number | null>>(null);
  const [selected, setSelected] = useState(initialValue);

  useEffect(() => {
    const t = setTimeout(() => {
      ref.current?.scrollToOffset({
        animated: false,
        offset: (initialValue - 1) * ITEM_HEIGHT,
      });
    }, 80);
    return () => clearTimeout(t);
  }, [initialValue]);

  const handleScrollEnd = (e: {
    nativeEvent: { contentOffset: { y: number } };
  }) => {
    const idx = Math.round(e.nativeEvent.contentOffset.y / ITEM_HEIGHT);
    const v = Math.max(1, Math.min(GOAL_MAX, idx + 1));
    setSelected(v);
    onChange(v);
  };

  return (
    <View style={{ height: ITEM_HEIGHT * VISIBLE, overflow: 'hidden' }}>
      <View
        pointerEvents="none"
        style={{
          borderRadius: 14,
          backgroundColor: '#ede8fb',
          height: ITEM_HEIGHT,
          left: 0,
          position: 'absolute',
          right: 0,
          top: ITEM_HEIGHT * HALF,
        }}
      />
      <FlatList
        ref={ref}
        data={ITEMS}
        decelerationRate="fast"
        extraData={selected}
        keyExtractor={(_, i) => String(i)}
        onMomentumScrollEnd={handleScrollEnd}
        renderItem={({ item, index }) => {
          if (item === null) return <View style={{ height: ITEM_HEIGHT }} />;
          const dist = Math.abs(index - HALF - (selected - 1));
          const isSelected = dist === 0;
          return (
            <View
              style={{
                alignItems: 'center',
                height: ITEM_HEIGHT,
                justifyContent: 'center',
              }}
            >
              <Text
                style={{
                  color: isSelected ? '#7851A9' : dist === 1 ? '#888' : '#ccc',
                  fontSize: isSelected ? 34 : dist === 1 ? 24 : 18,
                  fontWeight: isSelected ? '700' : '400',
                }}
              >
                {item}
              </Text>
            </View>
          );
        }}
        showsVerticalScrollIndicator={false}
        snapToInterval={ITEM_HEIGHT}
      />
    </View>
  );
}

import { memo, useEffect } from 'react';
import { View } from 'react-native';
import Animated, {
  Easing,
  useAnimatedProps,
  useSharedValue,
  withTiming,
} from 'react-native-reanimated';
import Svg, { Circle } from 'react-native-svg';

import { Text } from '@/components/atoms/Text';
import { motion } from '@/shared/lib/animations';

const AnimatedCircle = Animated.createAnimatedComponent(Circle);

type ProgressRingProps = {
  label?: string;
  progress: number;
  progressColor?: string;
  size?: number;
  strokeWidth?: number;
  textClassName?: string;
  trackColor?: string;
};

export const ProgressRing = memo(
  ({
    label,
    progress,
    progressColor = '#7851A9',
    size = 92,
    strokeWidth = 10,
    textClassName = 'text-brand dark:text-brand-soft',
    trackColor = 'rgba(17, 24, 39, 0.08)',
  }: ProgressRingProps) => {
    const radius = (size - strokeWidth) / 2;
    const circumference = radius * 2 * Math.PI;
    const normalizedProgress = Math.max(0, Math.min(100, progress));
    const fontSize = Math.round((size - strokeWidth * 2) * 0.38);
    const progressValue = useSharedValue(0);

    useEffect(() => {
      progressValue.value = withTiming(normalizedProgress, {
        duration: motion.slow,
        easing: Easing.out(Easing.cubic),
      });
    }, [normalizedProgress, progressValue]);

    const animatedProps = useAnimatedProps(() => ({
      strokeDashoffset:
        circumference - (circumference * progressValue.value) / 100,
    }));

    return (
      <View className="items-center justify-center">
        <Svg height={size} width={size}>
          <Circle
            cx={size / 2}
            cy={size / 2}
            fill="transparent"
            r={radius}
            stroke={trackColor}
            strokeWidth={strokeWidth}
          />
          <AnimatedCircle
            animatedProps={animatedProps}
            cx={size / 2}
            cy={size / 2}
            fill="transparent"
            r={radius}
            rotation="-90"
            stroke={progressColor}
            strokeDasharray={circumference}
            strokeLinecap="round"
            strokeWidth={strokeWidth}
            originX={size / 2}
            originY={size / 2}
          />
        </Svg>
        <View className="absolute items-center gap-0.5">
          <Text
            className={textClassName}
            style={{ fontSize, fontWeight: '600' }}
            variant="title"
          >
            {normalizedProgress}%
          </Text>
          {label ? (
            <Text
              className="text-center text-[11px] text-textMuted dark:text-textMutedDark"
              variant="caption"
            >
              {label}
            </Text>
          ) : null}
        </View>
      </View>
    );
  },
);

ProgressRing.displayName = 'ProgressRing';

