            {/* Reviews sub-tab */}
            {infoSubTab === 'reviews' && (
              <>
                {myRating || userReview ? (
                  <View className="mx-5 mb-4 gap-3">
                    <View
                      className="rounded-[10px] border border-[#d9d9d9] bg-[#f9f9f9] p-4"
                      style={{
                        elevation: 2,
                        shadowColor: '#000',
                        shadowOffset: { width: 0, height: 0 },
                        shadowOpacity: 0.1,
                        shadowRadius: 4,
                      }}
                    >
                      <View className="mb-3 flex-row items-center justify-between">
