function TrendingBookCard({
  book,
  onAdd,
}: {
  book: Book;
  onAdd: (book: Book) => void;
}) {
  const router = useRouter();
  const fullStars = Math.round(book.rating);
  return (
    <Pressable
      accessibilityLabel={`${book.title} by ${book.author}`}
      accessibilityRole="button"
      className="flex-1 overflow-hidden rounded-[10px] border border-[#e8e8e8] bg-white"
      style={{
        shadowColor: '#000',
        shadowOffset: { width: 0, height: 1 },
        shadowOpacity: 0.08,
        shadowRadius: 4,
        elevation: 2,
      }}
      onPress={() => router.push(bookHref(book.id))}
    >
      {/* Cover — portrait, fills card width */}
      {book.coverImage ? (
        <Image
          resizeMode="cover"
          source={{ uri: book.coverImage }}
          style={{ width: '100%', aspectRatio: 0.75 }}
        />
      ) : (
        <View
          className="w-full items-center justify-center bg-[#f1edf8]"
          style={{ aspectRatio: 0.75 }}
        >
          <Ionicons color="#7851A9" name="book-outline" size={36} />
        </View>
      )}

      {/* Info */}
      <View className="gap-0.5 p-2 pb-2.5">
        <Text
          className="text-[12px] font-semibold leading-tight text-black"
          numberOfLines={2}
        >
          {book.title}
        </Text>
        <Text className="text-[10px] text-[#6d7a88]" numberOfLines={1}>
          by {book.author}
        </Text>

        {/* Stars + rating + genre */}
        <View className="flex-row flex-wrap items-center gap-x-0.5 pt-0.5">
          {Array.from({ length: 5 }).map((_, i) => (
            <Ionicons
              key={i}
              color={i < fullStars ? '#F5C518' : '#D9D9D9'}
              name="star"
              size={10}
            />
          ))}
          {book.rating > 0 && (
            <Text className="text-[10px] text-[#6d7a88]">
              {book.rating.toFixed(1)}
            </Text>
          )}
          <Text className="text-[10px] text-[#6d7a88]">{book.genres[0]}</Text>
        </View>

        {/* Add button */}
        <Pressable
          accessibilityLabel={`Add ${book.title} to library`}
          accessibilityRole="button"
          className="mt-1 items-center rounded-[6px] bg-[#7851A9] py-1.5"
          onPress={(e) => {
            e.stopPropagation();
            onAdd(book);
          }}
        >
          <Text className="text-[11px] font-semibold text-white">+ Add</Text>
        </Pressable>
      </View>
    </Pressable>
  );
}

function BookListRow({
  book,
  onAdd,
  onEdit,
}: {
  book: Book;
  onAdd?: (book: Book) => void;
  onEdit?: (book: Book) => void;
}) {
  const router = useRouter();
  return (
    <Pressable
      accessibilityLabel={`${book.title} by ${book.author}`}
      accessibilityRole="button"
      className="flex-row items-center gap-3 py-2"
      onPress={() => router.push(bookHref(book.id))}
    >
      {book.coverImage ? (
        <Image
          className="h-[60px] w-[44px] rounded-[8px]"
          source={{ uri: book.coverImage }}
        />
      ) : (
        <View className="h-[60px] w-[44px] items-center justify-center rounded-[8px] bg-[#f1edf8]">
          <Ionicons color="#7851A9" name="book-outline" size={20} />
        </View>
      )}
      <View className="flex-1 gap-0.5">
        <Text
          className="text-[13px] font-semibold text-black"
          numberOfLines={1}
        >
          {book.title}
        </Text>
        <Text className="text-[12px] text-[#6d7a88]">{book.author}</Text>
        {book.publisher && (
          <Text className="text-[11px] text-[#9b9b9b]" numberOfLines={1}>
            {book.publisher}
          </Text>
        )}
        {book.rating > 0 && (
          <View className="flex-row items-center gap-1">
            <Ionicons color="#F5C518" name="star" size={11} />
            <Text className="text-[11px] text-[#6d7a88]">
              {book.rating.toFixed(1)}
            </Text>
          </View>
        )}
      </View>
      <View className="flex-row items-center gap-2">
        <View className="rounded-[5px] bg-[#f1edf8] px-2 py-0.5">
          <Text className="text-[11px] text-[#7851A9]">{book.genres[0]}</Text>
        </View>
        {onEdit && book.id.startsWith('custom-') && (
          <Pressable
            accessibilityLabel={`Edit ${book.title}`}
            className="rounded-full bg-[#f1edf8] p-1"
            hitSlop={8}
            onPress={(e) => {
              e.stopPropagation();
              onEdit(book);
            }}
          >
            <Ionicons color="#7851A9" name="pencil" size={14} />
          </Pressable>
        )}
        {onAdd && (
          <Pressable
            accessibilityLabel={`Add ${book.title} to library`}
            className="rounded-full bg-[#7851A9] p-1"
            hitSlop={8}
            onPress={(e) => {
              e.stopPropagation();
              onAdd(book);
            }}
          >
            <Ionicons color="white" name="add" size={14} />
          </Pressable>
        )}
      </View>
    </Pressable>
  );
}

export const DiscoverScreen = () => {
  const [query, setQuery] = useState('');
  const [searchMode, setSearchMode] = useState<SearchMode>('default');
  const [activeTab, setActiveTab] = useState<DiscoverTab>('genres');
  const [selectedGenre, setSelectedGenre] = useState<string | null>(null);
  const [scannerVisible, setScannerVisible] = useState(false);
  const [addModalVisible, setAddModalVisible] = useState(false);
  const [editingBook, setEditingBook] = useState<Book | undefined>(undefined);
  const [addToShelfBook, setAddToShelfBook] = useState<Book | null>(null);
  const [dialog, setDialog] = useState<{
    buttons: DialogButton[];
    message?: string;
    title: string;
  } | null>(null);

  const user = useAuthStore((s) => s.user);
  const addBook = useBookStore((s) => s.addBook);

  const { data: searchResults = [], isFetching: isSearching } =
    useBookSearch(query, searchMode);
  const { data: trendingBooks = [], isFetching: isTrendingLoading } =
    useNytBestsellers();
  const { data: genreBooks = [], isFetching: isGenreLoading } =
    useGenreBooks(selectedGenre);

  const isSearchMode = query.trim().length >= 2;

  const handleAddBook = (book: Book) => {
    if (!user) return;
    setAddToShelfBook(book);
  };

  const tabs: { id: DiscoverTab; label: string }[] = [
    { id: 'trending', label: 'Trending' },
    { id: 'genres', label: 'Genres' },
    { id: 'people', label: 'People' },
  ];

  return (
    <SafeAreaView className="flex-1 bg-[#fdfdfd]" edges={['top']}>
      <ScrollView
        bounces={false}
        contentContainerStyle={{ paddingBottom: 100 }}
        keyboardShouldPersistTaps="handled"
        showsVerticalScrollIndicator={false}
      >
        {/* Search bar */}
        <View className="px-5 pb-3 pt-4">
          <View className="flex-row items-center gap-2">
            <View
              className="flex-1 flex-row items-center gap-2 rounded-[10px] border border-[#d9d9d9] bg-[#f9f9f9] px-4"
              style={{ height: 45 }}
            >
              <Ionicons color="#6d7a88" name="search-outline" size={20} />
              <TextInput
                className="flex-1 text-[14px] text-black"
                onChangeText={setQuery}
                placeholder={searchMode === 'publisher' ? 'Search by publisher name' : 'Search books, authors or genres'}
                placeholderTextColor="rgba(109,122,136,0.6)"
                value={query}
              />
              {isSearching && (
                <ActivityIndicator color="#7851A9" size="small" />
              )}
              {query.length > 0 && !isSearching && (
                <Pressable
                  accessibilityLabel="Clear search"
                  onPress={() => setQuery('')}
                >
                  <Ionicons color="#6d7a88" name="close-circle" size={18} />
                </Pressable>
              )}
            </View>
            {/* Scan barcode button */}
            <Pressable
              accessibilityLabel="Scan book barcode"
              accessibilityRole="button"
              className="items-center justify-center rounded-[10px] border border-[#d9d9d9] bg-[#f9f9f9]"
              hitSlop={4}
              onPress={() => setScannerVisible(true)}
              style={{ width: 45, height: 45 }}
            >
              <Ionicons color="#7851A9" name="barcode-outline" size={22} />
            </Pressable>
            {/* Add book button */}
            <Pressable
              accessibilityLabel="Add a book to database"
              accessibilityRole="button"
              className="items-center justify-center rounded-[10px] bg-[#7851A9]"
              hitSlop={4}
              onPress={() => setAddModalVisible(true)}
              style={{ width: 45, height: 45 }}
            >
              <Ionicons color="white" name="add" size={24} />
            </Pressable>
          </View>

          {/* Search mode toggle */}
          <View className="mt-2.5 flex-row gap-2">
            <Pressable
              className="flex-row items-center gap-1 rounded-full px-3 py-1.5"
              onPress={() => setSearchMode('default')}
              style={{ backgroundColor: searchMode === 'default' ? '#7851A9' : '#f1edf8' }}
            >
              <Ionicons
                color={searchMode === 'default' ? 'white' : '#7851A9'}
                name="book-outline"
                size={12}
              />
              <Text
                className={`text-[12px] font-medium ${searchMode === 'default' ? 'text-white' : 'text-[#7851A9]'}`}
              >
                Title / Author
              </Text>
            </Pressable>
            <Pressable
              className="flex-row items-center gap-1 rounded-full px-3 py-1.5"
              onPress={() => setSearchMode('publisher')}
              style={{ backgroundColor: searchMode === 'publisher' ? '#7851A9' : '#f1edf8' }}
            >
              <Ionicons
                color={searchMode === 'publisher' ? 'white' : '#7851A9'}
                name="business-outline"
                size={12}
              />
              <Text
                className={`text-[12px] font-medium ${searchMode === 'publisher' ? 'text-white' : 'text-[#7851A9]'}`}
              >
                Publisher
              </Text>
            </Pressable>
          </View>
        </View>

        {/* Search results */}
        {isSearchMode && (
          <View className="gap-1 px-5">
            {searchResults.length === 0 && !isSearching && (
              <Text className="py-6 text-center text-[14px] text-[#6d7a88]">
                No results found.
              </Text>
            )}
            {searchResults.map((book) => (
              <BookListRow
                key={book.id}
                book={book}
                onAdd={handleAddBook}
                onEdit={setEditingBook}
              />
            ))}
          </View>
        )}

        {/* Tabs — only shown when not searching */}
        {!isSearchMode && (
          <>
            <View
              className="mx-5 mb-4 flex-row rounded-[8px] border border-[#d9d9d9] bg-[#f9f9f9]"
              style={{ height: 41 }}
            >
              {tabs.map((tab, index) => {
                const isActive = activeTab === tab.id;
                return (
                  <Pressable
                    key={tab.id}
                    accessibilityLabel={tab.label}
                    accessibilityRole="tab"
                    className="flex-1 items-center justify-center"
                    onPress={() => {
                      setActiveTab(tab.id);
                      setSelectedGenre(null);
                    }}
                    style={
                      isActive && {
                        backgroundColor: '#a0c4a7',
                        borderTopLeftRadius: index === 0 ? 7 : 0,
                        borderBottomLeftRadius: index === 0 ? 7 : 0,
                        borderTopRightRadius: index === 2 ? 7 : 0,
                        borderBottomRightRadius: index === 2 ? 7 : 0,
                      }
                    }
                  >
                    <View className="flex-row items-center gap-1">
                      <Text
                        className={`text-[14px] ${isActive ? 'text-white' : 'text-black'}`}
                      >
                        {tab.label}
                      </Text>
                      {isActive && (
                        <Ionicons color="white" name="chevron-down" size={14} />
                      )}
                    </View>
                  </Pressable>
                );
              })}
            </View>

            {/* Trending tab */}
            {activeTab === 'trending' && (
              <View className="px-4">
                {isTrendingLoading && (
                  <ActivityIndicator className="py-6" color="#7851A9" />
                )}
                {!isTrendingLoading && trendingBooks.length === 0 && (
                  <Text className="py-6 text-center text-[14px] text-[#6d7a88]">
                    Trending books unavailable. Add an NYT API key to enable
                    this.
                  </Text>
                )}
                {trendingBooks
                  .reduce<Book[][]>((rows, book, i) => {
                    if (i % 2 === 0) rows.push([book]);
                    else rows[rows.length - 1]!.push(book);
                    return rows;
                  }, [])
                  .map((pair, rowIdx) => (
                    <View key={rowIdx} className="mb-3 flex-row gap-3">
                      {pair.map((book) => (
                        <TrendingBookCard
                          key={book.id}
                          book={book}
                          onAdd={handleAddBook}
                        />
                      ))}
                      {pair.length === 1 && <View className="flex-1" />}
                    </View>
                  ))}
              </View>
            )}

            {/* Genres tab */}
            {activeTab === 'genres' && (
              <View className="gap-4 px-5">
                {/* Genre pills */}
                <ScrollView
                  contentContainerStyle={{ gap: 8 }}
                  horizontal
                  showsHorizontalScrollIndicator={false}
                >
                  <Pressable
                    accessibilityLabel="All genres"
                    className="rounded-full px-5 py-2.5"
                    onPress={() => setSelectedGenre(null)}
                    style={{
                      backgroundColor: !selectedGenre ? '#7851A9' : '#f1edf8',
                    }}
                  >
                    <Text
                      className={`text-[14px] ${
                        !selectedGenre ? 'text-white' : 'text-[#7851A9]'
                      }`}
                    >
                      All
                    </Text>
                  </Pressable>
                  {GENRE_CARDS.map((genre) => (
                    <Pressable
                      key={genre.query}
                      accessibilityLabel={genre.label}
                      className="rounded-full px-5 py-2.5"
                      onPress={() =>
                        setSelectedGenre(
                          selectedGenre === genre.query ? null : genre.query,
                        )
                      }
                      style={{
                        backgroundColor:
                          selectedGenre === genre.query ? '#7851A9' : '#f1edf8',
                      }}
                    >
                      <Text
                        className={`text-[14px] ${
                          selectedGenre === genre.query
                            ? 'text-white'
                            : 'text-[#7851A9]'
                        }`}
                      >
                        {genre.label}
                      </Text>
                    </Pressable>
                  ))}
                </ScrollView>

                {/* Books */}
                {isGenreLoading && <ActivityIndicator color="#7851A9" />}
                {!isGenreLoading && !selectedGenre && (
                  <Text className="py-6 text-center text-[14px] text-[#6d7a88]">
                    Choose a genre to explore books.
                  </Text>
                )}
                {!isGenreLoading &&
                  selectedGenre &&
                  genreBooks.length === 0 && (
                    <Text className="py-6 text-center text-[14px] text-[#6d7a88]">
                      No books found for this genre.
                    </Text>
                  )}
                {!isGenreLoading &&
                  selectedGenre &&
                  genreBooks
                    .reduce<Book[][]>((rows, book, i) => {
                      if (i % 2 === 0) rows.push([book]);
                      else rows[rows.length - 1]!.push(book);
                      return rows;
                    }, [])
                    .map((pair, rowIdx) => (
                      <View key={rowIdx} className="mb-1 flex-row gap-3">
                        {pair.map((book) => (
                          <TrendingBookCard
                            key={book.id}
                            book={book}
                            onAdd={handleAddBook}
                          />
                        ))}
                        {pair.length === 1 && <View className="flex-1" />}
                      </View>
                    ))}
              </View>
            )}

            {/* People tab */}
            {activeTab === 'people' && (
              <View className="items-center px-5 py-10">
                <Ionicons color="#d9d9d9" name="people-outline" size={48} />
                <Text className="mt-3 text-[14px] text-[#6d7a88]">
                  People discovery coming soon.
                </Text>
              </View>
            )}
          </>
        )}
      </ScrollView>
      {user && (
        <AddBookModal
          editBook={editingBook}
          userId={user.id}
          visible={addModalVisible || !!editingBook}
          onBookSaved={(book, status) => addBook(user.id, book, status)}
          onClose={() => {
            setAddModalVisible(false);
            setEditingBook(undefined);
          }}
        />
      )}
      <AddToShelfModal
        {...(addToShelfBook ? { book: addToShelfBook } : {})}
        bookApiId={addToShelfBook?.id ?? null}
        visible={addToShelfBook !== null}
        onClose={() => setAddToShelfBook(null)}
        onSaved={() => setQuery('')}
      />
      <AppDialog
        buttons={dialog?.buttons ?? []}
        message={dialog?.message}
        onClose={() => setDialog(null)}
        title={dialog?.title ?? ''}
        visible={!!dialog}
      />
      <BarcodeScannerModal
        visible={scannerVisible}
        onClose={() => setScannerVisible(false)}
        onScan={(isbn) => {
          setSearchMode('default');
          setQuery(isbn);
        }}
      />
    </SafeAreaView>
  );
};

import { Ionicons } from '@expo/vector-icons';
import { useRouter } from 'expo-router';
import { memo, useCallback, useMemo, useState } from 'react';
import {
  ActivityIndicator,
  Image,
  Pressable,
  ScrollView,
  TouchableOpacity,
  useWindowDimensions,
  View,
} from 'react-native';

import {
  Avatar,
  BookCard,
  Button,
  Card,
  Container,
  ProgressRing,
  Screen,
  Text,
} from '@/components';
import { getChallengeProgress } from '@/entities/challenge';
import { getInitials } from '@/entities/user';
import { useNytBestsellers } from '@/features/discover/hooks/useNytBestsellers';
import { WhatToReadNextCard } from '@/features/library/components/WhatToReadNextCard';
import { useCustomShelves } from '@/features/library/hooks/useCustomShelves';
import { useLibrarySections } from '@/features/library/hooks/useLibrarySections';
import { useLiveChallenge } from '@/features/library/hooks/useLiveChallenge';
import { useAuthStore } from '@/store/authStore';
import { useProfileStore } from '@/store/profileStore';
import type { Book } from '@/types';


const bookHref = (id: string, tab?: string) =>
  (tab ? `/book/${id}?tab=${tab}` : `/book/${id}`) as any;

const getGreeting = () => {
  const hour = new Date().getHours();
  if (hour < 12) return 'Good morning';
  if (hour < 18) return 'Good afternoon';
  return 'Good evening';
};

// ─── Sub-components ────────────────────────────────────────────────────────────

const StarRating = memo(({ rating }: { rating: number }) => (
  <View className="flex-row items-center gap-1">
    {[1, 2, 3, 4, 5].map((star) => (
      <Ionicons
        key={star}
        color={star <= Math.round(rating) ? '#F5A623' : '#D9D9D9'}
        name="star"
        size={12}
      />
    ))}
    <Text className="text-[12px] text-[#6d6d6d]" variant="caption">
      {rating.toFixed(1)}
    </Text>
  </View>
));
StarRating.displayName = 'StarRating';

const NowReadingCard = memo(
  ({ book, onPress }: { book: Book; onPress: () => void }) => {
    const coverSource = useMemo(() => ({ uri: book.coverImage }), [book.coverImage]);
    return (
      <Card className="overflow-hidden rounded-[20px] border-[#e8e8e8] bg-[#f9f9f9] p-0">
        <View className="flex-row gap-4 p-4">
          <Image
            className="h-[130px] w-[90px] rounded-[14px] bg-[#e0e0e0]"
            source={coverSource}
          />
          <View className="flex-1 justify-center gap-2">
            <Text
              className="text-[15px] font-semibold leading-[20px] text-black"
              numberOfLines={2}
              variant="body"
            >
              {book.title}
            </Text>
            <Text className="text-[13px] text-[#6d6d6d]" variant="caption">
              {book.author}
            </Text>
            <StarRating rating={book.rating} />
            <View className="mt-1 gap-1">
              <View className="h-[6px] overflow-hidden rounded-full bg-[#e5e5e5]">
                <View
                  className="h-full rounded-full bg-[#7851A9]"
                  style={{ width: `${book.progress}%` }}
                />
              </View>
              <Text className="text-[11px] text-[#9b9b9b]" variant="caption">
                {book.progress}% ·{' '}
                {Math.round((book.progress / 100) * (book.pages ?? 0))}/
                {book.pages ?? 0} pages
              </Text>
            </View>
          </View>
        </View>
        <View className="px-4 pb-4">
          <Button label="Continue reading" onPress={onPress} />
        </View>
      </Card>
    );
  },
);
NowReadingCard.displayName = 'NowReadingCard';

const ChallengeStrip = memo(({ onPress }: { onPress: () => void }) => {
  const { challenge } = useLiveChallenge();
  const progress = getChallengeProgress(challenge);

  return (
    <TouchableOpacity activeOpacity={0.85} onPress={onPress}>
      <Card className="rounded-[17px] border-[#d9d9d9] bg-[#f9f9f9] px-5 py-4">
        <View className="flex-row items-center justify-between gap-4">
          <View className="flex-1 gap-1">
            <Text className="text-[13px] text-[#6d6d6d]" variant="caption">
              {challenge.year} Reading Challenge
            </Text>
            <Text className="text-[22px] font-semibold text-[#7851A9]" variant="body">
              {challenge.completed}/{challenge.goal} books
            </Text>
            <Text className="text-[13px] text-black" variant="caption">
              {challenge.label}
            </Text>
          </View>
          <ProgressRing
            progress={progress}
            progressColor="#CC76D8"
            size={72}
            strokeWidth={10}
            textClassName="text-[#313C5D]"
            trackColor="#7851A9"
          />
        </View>
      </Card>
    </TouchableOpacity>
  );
});
ChallengeStrip.displayName = 'ChallengeStrip';

// ─── Main screen ───────────────────────────────────────────────────────────────

export const HomeScreen = memo(() => {
  const router = useRouter();
  const user = useAuthStore((s) => s.user);
  const { dnf = [], keepReading = [], wantToRead = [], finished = [], isFetching } = useLibrarySections();
  const { data: picks = [] } = useNytBestsellers();
  const { data: customShelves = [] } = useCustomShelves(user?.id ?? null);
  const widgets = useProfileStore((s) => s.homeWidgets);
  const { width: screenWidth } = useWindowDimensions();
  const firstName = user?.name?.split(' ')[0] ?? 'there';
  const initials = user ? getInitials(user) : '?';
  const CARD_WIDTH = screenWidth - 40;
  const CARD_GAP = 12;
  const [activeIndex, setActiveIndex] = useState(0);

  const renderWidget = useCallback(
    (id: string) => {
      switch (id) {
        case 'currentlyReading':
          return isFetching ? (
            <ActivityIndicator key="cr-loading" color="#7851A9" />
          ) : keepReading.length > 0 ? (
            <View key="currentlyReading" className="gap-3">
              <Text className="text-[17px] font-semibold text-black" variant="body">
                Now Reading
              </Text>
              <ScrollView
                className="-mx-5"
                contentContainerStyle={{ gap: CARD_GAP, paddingHorizontal: 20 }}
                decelerationRate="fast"
                horizontal
                onMomentumScrollEnd={(e) => {
                  setActiveIndex(
                    Math.round(e.nativeEvent.contentOffset.x / (CARD_WIDTH + CARD_GAP)),
                  );
                }}
                showsHorizontalScrollIndicator={false}
                snapToInterval={CARD_WIDTH + CARD_GAP}
              >
                {keepReading.map((book) => (
                  <View key={book.id} style={{ width: CARD_WIDTH }}>
                    <NowReadingCard
                      book={book}
                      onPress={() => router.push(bookHref(book.id, 'my-reading'))}
                    />
                  </View>
                ))}
              </ScrollView>
              {keepReading.length > 1 && (
                <View className="flex-row justify-center gap-1.5">
                  {keepReading.map((_, i) => (
                    <View
                      key={i}
                      className="rounded-full"
                      style={{
                        backgroundColor: i === activeIndex ? '#7851A9' : '#d9d9d9',
                        height: 6,
                        width: i === activeIndex ? 16 : 6,
                      }}
                    />
                  ))}
                </View>
              )}
            </View>
          ) : (
            <Card key="cr-empty" className="items-center gap-3 rounded-[20px] border-[#e8e8e8] bg-[#f9f9f9] py-8">
              <Ionicons color="#c0c0c0" name="book-outline" size={40} />
              <Text className="text-center text-[15px] text-[#9b9b9b]" variant="body">
                No books in progress.{'\n'}Head to Discover to find your next read.
              </Text>
            </Card>
          );

        case 'whatToReadNext':
          return (
            <WhatToReadNextCard
              key="whatToReadNext"
              customShelves={customShelves}
              wantToRead={wantToRead}
            />
          );

        case 'tbrShelf':
          return wantToRead.length > 0 ? (
            <View key="tbrShelf" className="gap-3">
              <View className="flex-row items-center justify-between">
                <View className="flex-row items-center gap-2">
                  <Text className="text-[17px] font-semibold text-black" variant="body">TBR</Text>
                  <View style={{ backgroundColor: '#ede9f7', borderRadius: 20, paddingHorizontal: 8, paddingVertical: 2 }}>
                    <Text className="text-[12px] font-semibold text-[#7851A9]" variant="caption">{wantToRead.length}</Text>
                  </View>
                </View>
                <Pressable onPress={() => router.push('/shelf/want-to-read' as any)} style={({ pressed }) => ({ opacity: pressed ? 0.6 : 1 })}>
                  <Text className="text-[13px] text-[#7851A9]" variant="body">See all</Text>
                </Pressable>
              </View>
              <ScrollView className="-mx-5" contentContainerStyle={{ gap: 10, paddingHorizontal: 20 }} horizontal showsHorizontalScrollIndicator={false}>
                {wantToRead.slice(0, 12).map((book) => (
                  <BookCard key={book.id} book={book} onPress={() => router.push(bookHref(book.id))} variant="compact" />
                ))}
              </ScrollView>
            </View>
          ) : null;

        case 'finished':
          return finished.length > 0 ? (
            <View key="finished" className="gap-3">
              <View className="flex-row items-center justify-between">
                <View className="flex-row items-center gap-2">
                  <Text className="text-[17px] font-semibold text-black" variant="body">Finished</Text>
                  <View style={{ backgroundColor: '#ede9f7', borderRadius: 20, paddingHorizontal: 8, paddingVertical: 2 }}>
                    <Text className="text-[12px] font-semibold text-[#7851A9]" variant="caption">{finished.length}</Text>
                  </View>
                </View>
                <Pressable onPress={() => router.push('/shelf/completed' as any)} style={({ pressed }) => ({ opacity: pressed ? 0.6 : 1 })}>
                  <Text className="text-[13px] text-[#7851A9]" variant="body">See all</Text>
                </Pressable>
              </View>
              <ScrollView className="-mx-5" contentContainerStyle={{ gap: 10, paddingHorizontal: 20 }} horizontal showsHorizontalScrollIndicator={false}>
                {finished.slice(0, 12).map((book) => (
                  <BookCard key={book.id} book={book} onPress={() => router.push(bookHref(book.id))} variant="compact" />
                ))}
              </ScrollView>
            </View>
          ) : null;

        case 'dnfShelf':
          return dnf.length > 0 ? (
            <View key="dnfShelf" className="gap-3">
              <View className="flex-row items-center justify-between">
                <View className="flex-row items-center gap-2">
                  <Text className="text-[17px] font-semibold text-black" variant="body">Did Not Finish</Text>
                  <View style={{ backgroundColor: '#fdecea', borderRadius: 20, paddingHorizontal: 8, paddingVertical: 2 }}>
                    <Text className="text-[12px] font-semibold text-[#c0392b]" variant="caption">{dnf.length}</Text>
                  </View>
                </View>
                <Pressable onPress={() => router.push('/shelf/dnf' as any)} style={({ pressed }) => ({ opacity: pressed ? 0.6 : 1 })}>
                  <Text className="text-[13px] text-[#7851A9]" variant="body">See all</Text>
                </Pressable>
              </View>
              <ScrollView className="-mx-5" contentContainerStyle={{ gap: 10, paddingHorizontal: 20 }} horizontal showsHorizontalScrollIndicator={false}>
                {dnf.slice(0, 12).map((book) => (
                  <BookCard key={book.id} book={book} onPress={() => router.push(bookHref(book.id))} variant="compact" />
                ))}
              </ScrollView>
            </View>
          ) : null;

        case 'readingChallenge':
          return <ChallengeStrip key="readingChallenge" onPress={() => router.push('/challenge' as any)} />;

        case 'customShelves':
          return customShelves.length > 0 ? (
            <View key="customShelves" className="gap-3">
              <View className="flex-row items-center justify-between">
                <Text className="text-[17px] font-semibold text-black" variant="body">My Shelves</Text>
                <Pressable onPress={() => router.push('/(tabs)/library' as any)} style={({ pressed }) => ({ opacity: pressed ? 0.6 : 1 })}>
                  <Text className="text-[13px] text-[#7851A9]" variant="body">See all</Text>
                </Pressable>
              </View>
              {customShelves.slice(0, 4).map((shelf) => (
                <Pressable key={shelf.id} onPress={() => router.push(`/custom-shelf/${shelf.id}` as any)} style={({ pressed }) => ({ opacity: pressed ? 0.8 : 1 })}>
                  <Card className="flex-row items-center rounded-[17px] border-[#d9d9d9] bg-[#f9f9f9] px-5 py-4">
                    <View className="mr-3 h-9 w-9 items-center justify-center rounded-full bg-[#ede9f7]">
                      <Ionicons color="#7851A9" name="bookmark-outline" size={16} />
                    </View>
                    <View className="flex-1">
                      <Text className="text-[15px] font-medium text-black" variant="body">{shelf.name}</Text>
                      <Text className="text-[12px] text-[#9b9b9b]" variant="body">{shelf.bookCount} book{shelf.bookCount !== 1 ? 's' : ''}</Text>
                    </View>
                    <Ionicons color="#c0c0c0" name="chevron-forward" size={16} />
                  </Card>
                </Pressable>
              ))}
            </View>
          ) : null;

        default:
          return null;
      }
    },
    [router, keepReading, wantToRead, finished, dnf, customShelves, isFetching, activeIndex, CARD_WIDTH, CARD_GAP],
  );

  return (
    <Screen className="bg-[#fdfdfd]" contentClassName="gap-6 pt-2" scrollable>
      <Container className="gap-6 pb-6">

        {/* Header */}
        <View className="flex-row items-center justify-between">
          <Ionicons color="#6d6d6d" name="notifications-outline" size={28} />
          <Avatar fallback={initials} size="sm" uri={user?.avatarUrl} />
        </View>

        {/* Greeting */}
        <View className="gap-1">
          <Text className="text-[14px] text-[#6d6d6d]" variant="caption">
            {getGreeting()},
          </Text>
          <Text className="text-[30px] font-semibold text-black" variant="display">
            {firstName} 👋
          </Text>
        </View>

        {/* Widgets in user-defined order */}
        {widgets.filter((w) => w.enabled).map((w) => renderWidget(w.id))}

        {/* Picks for you — always shown, not reorderable */}
        {picks.length > 0 && (
          <View className="gap-3">
            <Text className="text-[17px] font-semibold text-black" variant="body">
              Picks for you
            </Text>
            <ScrollView
              className="-mx-5"
              contentContainerClassName="gap-3 px-5"
              horizontal
              showsHorizontalScrollIndicator={false}
            >
              {picks.slice(0, 10).map((book) => (
                <BookCard key={book.id} book={book} onPress={() => router.push(bookHref(book.id))} variant="compact" />
              ))}
            </ScrollView>
          </View>
        )}

      </Container>
    </Screen>
  );
});

HomeScreen.displayName = 'HomeScreen';

import { Ionicons } from '@expo/vector-icons';
import { memo, useEffect, useRef, useState } from 'react';
import { ActivityIndicator, Alert, Modal, Pressable, ScrollView, View } from 'react-native';

import { Text } from '@/components/atoms/Text';
import { useBookShelfIds } from '@/features/library/hooks/useBookShelfIds';
import { useCustomShelves } from '@/features/library/hooks/useCustomShelves';
import { useUserBooks } from '@/features/library/hooks/useUserBooks';
import { useAuthStore } from '@/store/authStore';
import { useBookStore } from '@/store/bookStore';
import { useShelfStore } from '@/store/shelfStore';
import type { Book, BookStatus } from '@/types';

type Props = {
  book?: Book;
  bookApiId: string | null;
  onClose: () => void;
  onSaved?: () => void;
  visible: boolean;
};

const DEFAULT_SHELVES: { label: string; status: BookStatus }[] = [
  { label: 'TBR', status: 'want-to-read' },
  { label: 'Currently Reading', status: 'reading' },
  { label: 'Finished', status: 'completed' },
  { label: 'Did Not Finish', status: 'dnf' },
];

export const AddToShelfModal = memo(({ book, bookApiId, onClose, onSaved, visible }: Props) => {
  const userId = useAuthStore((s) => s.user?.id ?? null);
  const { data: shelves = [] } = useCustomShelves(userId);
  const { data: currentShelfIds = [] } = useBookShelfIds(bookApiId, userId);
  const { data: userBooks = [] } = useUserBooks(userId);
  const addBook = useBookStore((s) => s.addBook);
  const addBookToShelf = useShelfStore((s) => s.addBookToShelf);
  const removeBookFromShelf = useShelfStore((s) => s.removeBookFromShelf);
  const updateBookStatus = useBookStore((s) => s.updateBookStatus);

  const savedBook = userBooks.find((b) => b.id === bookApiId);
  const originalStatus = savedBook?.status ?? null;

  const [selectedStatus, setSelectedStatus] = useState<BookStatus | null>(originalStatus);
  const [selected, setSelected] = useState<Set<string>>(new Set());
  const [saving, setSaving] = useState(false);

  // Only initialize state when the modal transitions from closed → open,
  // not on background refetches that update currentShelfIds/originalStatus
  // while the user is actively making selections.
  const wasVisibleRef = useRef(false);
  useEffect(() => {
    const justOpened = visible && !wasVisibleRef.current;
    wasVisibleRef.current = visible;
    if (justOpened) {
      setSelectedStatus(originalStatus);
      setSelected(new Set(currentShelfIds));
    }
  }, [visible, currentShelfIds, originalStatus]);

  const toggleStatus = (status: BookStatus) => {
    setSelectedStatus((prev) => (prev === status ? null : status));
  };

  const toggle = (shelfId: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(shelfId)) next.delete(shelfId);
      else next.add(shelfId);
      return next;
    });
  };

  const handleSave = async () => {
    if (!userId || !bookApiId) return;
    setSaving(true);
    try {
      const isNewBook = !savedBook;
      const ops: Promise<void>[] = [];

      if (isNewBook && book) {
        ops.push(addBook(userId, book, selectedStatus));
      } else if (!isNewBook && selectedStatus !== originalStatus) {
        ops.push(updateBookStatus(userId, bookApiId, selectedStatus));
      }

      const toAdd = shelves.filter(
        (s) => selected.has(s.id) && !currentShelfIds.includes(s.id),
      );
      const toRemove = shelves.filter(
        (s) => !selected.has(s.id) && currentShelfIds.includes(s.id),
      );
      ops.push(...toAdd.map((s) => addBookToShelf(s.id, bookApiId, userId)));
      ops.push(...toRemove.map((s) => removeBookFromShelf(s.id, bookApiId, userId)));

      await Promise.all(ops);
      onSaved?.();
      onClose();
    } catch (e) {
      Alert.alert('Error', e instanceof Error ? e.message : 'Could not save. Please try again.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <Modal animationType="slide" transparent visible={visible}>
      <Pressable
        className="flex-1 justify-end bg-black/40"
        onPress={onClose}
      >
        <Pressable
          className="rounded-t-[24px] bg-white px-6 pb-10 pt-5"
          onPress={() => {}}
        >
          <View className="mb-1 h-1 w-10 self-center rounded-full bg-[#e0e0e0]" />
          <Text className="mb-4 mt-3 text-[18px] font-semibold text-black" variant="body">
            Bookshelves
          </Text>

          <ScrollView
            bounces={false}
            showsVerticalScrollIndicator={false}
            style={{ maxHeight: 360 }}
          >
            {/* Default shelves */}
            <Text className="mb-1 text-[11px] font-semibold uppercase tracking-widest text-[#9b9b9b]" variant="body">
              Default
            </Text>
            {DEFAULT_SHELVES.map(({ label, status }) => {
              const isChecked = selectedStatus === status;
              return (
                <Pressable
                  key={status}
                  className="flex-row items-center gap-3 py-3"
                  onPress={() => toggleStatus(status)}
                >
                  <View
                    className="h-6 w-6 items-center justify-center rounded-[6px]"
                    style={{
                      backgroundColor: isChecked ? '#7851A9' : '#f0f0f0',
                      borderColor: isChecked ? '#7851A9' : '#d0d0d0',
                      borderWidth: 1.5,
                    }}
                  >
                    {isChecked && (
                      <Ionicons color="#fff" name="checkmark" size={14} />
                    )}
                  </View>
                  <Text className="flex-1 text-[15px] text-black" variant="body">
                    {label}
                  </Text>
                </Pressable>
              );
            })}

            {/* Divider */}
            <View className="my-3 h-px bg-[#f0f0f0]" />

            {/* Custom shelves */}
            <Text className="mb-1 text-[11px] font-semibold uppercase tracking-widest text-[#9b9b9b]" variant="body">
              Custom
            </Text>
            {shelves.length === 0 ? (
              <View className="py-3">
                <Text className="text-[14px] text-[#9b9b9b]" variant="body">
                  No custom shelves yet. Create one from your Library.
                </Text>
              </View>
            ) : (
              shelves.map((shelf) => {
                const isChecked = selected.has(shelf.id);
                return (
                  <Pressable
                    key={shelf.id}
                    className="flex-row items-center gap-3 py-3"
                    onPress={() => toggle(shelf.id)}
                  >
                    <View
                      className="h-6 w-6 items-center justify-center rounded-[6px]"
                      style={{
                        backgroundColor: isChecked ? '#7851A9' : '#f0f0f0',
                        borderColor: isChecked ? '#7851A9' : '#d0d0d0',
                        borderWidth: 1.5,
                      }}
                    >
                      {isChecked && (
                        <Ionicons color="#fff" name="checkmark" size={14} />
                      )}
                    </View>
                    <Text className="flex-1 text-[15px] text-black" variant="body">
                      {shelf.name}
                    </Text>
                    <Text className="text-[13px] text-[#9b9b9b]" variant="body">
                      {shelf.bookCount} book{shelf.bookCount !== 1 ? 's' : ''}
                    </Text>
                  </Pressable>
                );
              })
            )}
          </ScrollView>

          <Pressable
            className="mt-4 items-center justify-center rounded-[12px] py-3.5"
            disabled={saving}
            onPress={() => void handleSave()}
            style={{ backgroundColor: '#7851A9', opacity: saving ? 0.6 : 1 }}
          >
            {saving ? (
              <ActivityIndicator color="#fff" size="small" />
            ) : (
              <Text className="text-[15px] font-semibold text-white" variant="body">
                Save
              </Text>
            )}
          </Pressable>
        </Pressable>
      </Pressable>
    </Modal>
  );
});

AddToShelfModal.displayName = 'AddToShelfModal';

import { memo, useState } from 'react';
import { ActivityIndicator, Modal, Pressable, TextInput, View } from 'react-native';

import { Text } from '@/components/atoms/Text';
import { useAuthStore } from '@/store/authStore';
import { useShelfStore } from '@/store/shelfStore';

type Props = {
  onClose: () => void;
  visible: boolean;
};

export const CreateShelfModal = memo(({ onClose, visible }: Props) => {
  const userId = useAuthStore((s) => s.user?.id ?? null);
  const createShelf = useShelfStore((s) => s.createShelf);
  const [name, setName] = useState('');
  const [saving, setSaving] = useState(false);

  const handleCreate = async () => {
    if (!userId || !name.trim()) return;
    setSaving(true);
    try {
      await createShelf(userId, name.trim());
      setName('');
      onClose();
    } finally {
      setSaving(false);
    }
  };

  const handleClose = () => {
    setName('');
    onClose();
  };

  return (
    <Modal animationType="fade" transparent visible={visible}>
      <Pressable
        className="flex-1 items-center justify-center bg-black/40"
        onPress={handleClose}
      >
        <Pressable
          className="mx-6 w-full rounded-[18px] bg-white px-6 py-6"
          onPress={() => {}}
        >
          <Text className="mb-4 text-[18px] font-semibold text-black" variant="body">
            New shelf
          </Text>
          <TextInput
            autoFocus
            className="rounded-[10px] border border-[#d9d9d9] bg-[#f9f9f9] px-4 text-[15px] text-black"
            maxLength={50}
            onChangeText={setName}
            onSubmitEditing={() => void handleCreate()}
            placeholder="Shelf name"
            placeholderTextColor="#aaa"
            returnKeyType="done"
            style={{ height: 48 }}
            value={name}
          />
          <View className="mt-5 flex-row gap-3">
            <Pressable
              className="flex-1 items-center justify-center rounded-[10px] border border-[#d9d9d9] py-3"
              onPress={handleClose}
            >
              <Text className="text-[14px] font-medium text-[#6d7a88]" variant="body">
                Cancel
              </Text>
            </Pressable>
            <Pressable
              className="flex-[2] items-center justify-center rounded-[10px] py-3"
              disabled={saving || !name.trim()}
              onPress={() => void handleCreate()}
              style={{
                backgroundColor: '#7851A9',
                opacity: saving || !name.trim() ? 0.5 : 1,
              }}
            >
              {saving ? (
                <ActivityIndicator color="#fff" size="small" />
              ) : (
                <Text className="text-[14px] font-semibold text-white" variant="body">
                  Create
                </Text>
              )}
            </Pressable>
          </View>
        </Pressable>
      </Pressable>
    </Modal>
  );
});

