RenameModal.displayName = 'RenameModal';

export const CustomShelfScreen = memo(
  ({ shelf }: { shelf: CustomShelf }) => {
    const router = useRouter();
    const user = useAuthStore((s) => s.user);
    const { width: screenWidth } = useWindowDimensions();
    const { data: books = [], isFetching } = useShelfBooks(shelf.id);
    const removeBookFromShelf = useShelfStore((s) => s.removeBookFromShelf);
    const deleteShelf = useShelfStore((s) => s.deleteShelf);
    const renameShelf = useShelfStore((s) => s.renameShelf);
    const archiveShelf = useShelfStore((s) => s.archiveShelf);
    const unarchiveShelf = useShelfStore((s) => s.unarchiveShelf);
    const [addModalVisible, setAddModalVisible] = useState(false);
    const [renameVisible, setRenameVisible] = useState(false);

    const itemWidth = Math.floor(
      (screenWidth - HORIZONTAL_PADDING * 2 - COLUMN_GAP * (NUM_COLUMNS - 1)) /
        NUM_COLUMNS,
    );

    const handleBookPress = useCallback(
      (id: string) => router.push(`/book/${id}` as any),
      [router],
    );

    const handleLongPress = useCallback(
      (bookId: string) => {
        if (!user) return;
        Alert.alert(
          'Remove from shelf',
          'This will remove the book from this shelf only. It will stay in your library.',
          [
            {
              text: 'Remove from shelf',
              style: 'destructive',
              onPress: () => void removeBookFromShelf(shelf.id, bookId, user.id),
            },
            { style: 'cancel', text: 'Cancel' },
          ],
        );
      },
      [shelf.id, removeBookFromShelf, user],
    );

    const handleAddPress = useCallback(() => {
      Alert.alert('Add a book', 'How would you like to add a book?', [
        {
          text: 'Search / Discover',
          onPress: () => router.push('/(tabs)/discover' as any),
        },
        { text: 'Enter manually', onPress: () => setAddModalVisible(true) },
        { style: 'cancel', text: 'Cancel' },
      ]);
    }, [router]);

    const handleMenuPress = useCallback(() => {
      Alert.alert(shelf.name, undefined, [
        { text: 'Rename', onPress: () => setRenameVisible(true) },
        shelf.isArchived
          ? {
              text: 'Unarchive',
              onPress: () => {
                if (!user) return;
                Alert.alert(
                  'Unarchive shelf',
                  `"${shelf.name}" will appear in your main shelves again.`,
                  [
                    {
                      text: 'Unarchive',
                      onPress: async () => {
                        await unarchiveShelf(user.id, shelf.id);
                        router.back();
                      },
                    },
                    { style: 'cancel', text: 'Cancel' },
                  ],
                );
              },
            }
          : {
              text: 'Archive shelf',
              onPress: () => {
                if (!user) return;
                Alert.alert(
                  'Archive shelf',
                  `"${shelf.name}" will be hidden from your main shelves. You can unarchive it any time.`,
                  [
                    {
                      text: 'Archive',
                      onPress: async () => {
                        await archiveShelf(user.id, shelf.id);
                        router.back();
                      },
                    },
                    { style: 'cancel', text: 'Cancel' },
                  ],
                );
              },
            },
        {
          text: 'Delete shelf',
          style: 'destructive',
          onPress: () => {
            Alert.alert(
              'Delete shelf',
              `Delete "${shelf.name}"? Books won't be removed from your library.`,
              [
                {
                  text: 'Delete',
                  style: 'destructive',
                  onPress: async () => {
                    if (!user) return;
                    await deleteShelf(user.id, shelf.id);
                    router.back();
                  },
                },
                { style: 'cancel', text: 'Cancel' },
              ],
            );
          },
        },
        { style: 'cancel', text: 'Cancel' },
      ]);
    }, [shelf, deleteShelf, archiveShelf, unarchiveShelf, user, router]);

    const handleRename = useCallback(
      async (name: string) => {
        if (!user || !name.trim()) return;
        setRenameVisible(false);
        await renameShelf(user.id, shelf.id, name.trim());
      },
      [user, shelf.id, renameShelf],
    );

    const allItems: GridItem[] = [
      ...books.map((book): GridItem => ({ type: 'book', book })),
      ...(!shelf.isArchived ? [{ type: 'add' } as GridItem] : []),
    ];
    const rem = allItems.length % NUM_COLUMNS;
    if (rem !== 0) {
      for (let i = 0; i < NUM_COLUMNS - rem; i++) allItems.push({ type: 'spacer' });
    }
    const rows: GridItem[][] = [];
    for (let i = 0; i < allItems.length; i += NUM_COLUMNS) {
      rows.push(allItems.slice(i, i + NUM_COLUMNS));
    }

    return (
      <SafeAreaView className="flex-1 bg-[#fdfdfd]" edges={['top']}>
        <View className="px-5 pb-2 pt-2">
          <Pressable
            className="mb-3 flex-row items-center gap-1 self-start"
            onPress={() => router.back()}
            style={({ pressed }) => ({ opacity: pressed ? 0.7 : 1 })}
          >
            <Ionicons color="#6d6d6d" name="chevron-back" size={20} />
            <Text className="text-[14px] text-[#6d6d6d]" variant="body">
              Library
            </Text>
          </Pressable>
          <View className="flex-row items-end justify-between">
            <View className="flex-1 gap-1">
              <Text
                className="text-[24px] font-bold text-black"
                numberOfLines={1}
                variant="body"
              >
                {shelf.name}
              </Text>
              {shelf.isArchived && (
                <View className="flex-row items-center gap-1 self-start rounded-full bg-[#f0f0f0] px-2.5 py-0.5">
                  <Ionicons color="#9b9b9b" name="archive-outline" size={11} />
                  <Text className="text-[11px] text-[#9b9b9b]" variant="body">
                    Archived
                  </Text>
                </View>
              )}
            </View>
            <View className="flex-row items-center gap-3">
              <Text className="mb-0.5 text-[13px] text-[#9b9b9b]" variant="body">
                {books.length} book{books.length !== 1 ? 's' : ''}
              </Text>
              <Pressable
                hitSlop={10}
                onPress={handleMenuPress}
                style={({ pressed }) => ({ opacity: pressed ? 0.6 : 1 })}
              >
                <Ionicons color="#6d6d6d" name="ellipsis-horizontal" size={20} />
              </Pressable>
            </View>
          </View>
        </View>

        {isFetching && books.length === 0 ? (
          <ActivityIndicator className="mt-10" color="#7851A9" />
        ) : (
          <ScrollView
            contentContainerStyle={{
              paddingBottom: 100,
              paddingHorizontal: HORIZONTAL_PADDING,
              paddingTop: 12,
            }}
            showsVerticalScrollIndicator={false}
          >
            {rows.map((row, rowIdx) => (
              <View
                key={rowIdx}
                style={{
                  alignItems: 'flex-start',
                  flexDirection: 'row',
                  columnGap: COLUMN_GAP,
                  marginBottom: rowIdx < rows.length - 1 ? COLUMN_GAP : 0,
                }}
              >
                {row.map((item, colIdx) => {
                  if (item.type === 'spacer') {
                    return <View key={`spacer-${colIdx}`} style={{ width: itemWidth }} />;
                  }
                  if (item.type === 'add') {
                    return (
                      <AddBookTile
                        key="add"
                        itemWidth={itemWidth}
                        onPress={handleAddPress}
                      />
                    );
                  }
                  return (
                    <BookGridItem
                      key={item.book.id}
                      book={item.book}
                      itemWidth={itemWidth}
                      onLongPress={handleLongPress}
                      onPress={handleBookPress}
                    />
                  );
                })}
              </View>
            ))}
          </ScrollView>
        )}

        {user && (
          <AddBookModal
            userId={user.id}
            visible={addModalVisible}
            onClose={() => setAddModalVisible(false)}
            onBookSaved={(book) => {
              router.push(`/book/${book.id}` as any);
            }}
          />
        )}

        <RenameModal
          currentName={shelf.name}
          visible={renameVisible}
          onClose={() => setRenameVisible(false)}
          onSave={(name) => void handleRename(name)}
        />
      </SafeAreaView>
    );
  },
);

