          variant="body"
        >
          {book.title}
        </Text>
        <Text className="text-[12px] text-[#6d6d6d]" variant="caption">
          {book.author}
        </Text>
        <View className="mt-0.5 flex-row items-center gap-1">
          {[1, 2, 3, 4, 5].map((s) => (
            <Ionicons
              key={s}
              color={
                s <= Math.round(book.myRating ?? book.rating)
                  ? '#F5A623'
